// Summary: Tests FloatingBar rendering, region role gating, scroll button visibility/disabled state, callbacks, and slot passthrough.

import '@testing-library/jest-dom';
import { fireEvent, render, screen } from '@testing-library/react';
import * as React from 'react';
import { FloatingBar } from './FloatingBar';

describe('FloatingBar', () => {
  it('renders provided content', () => {
    render(<FloatingBar content={<span>Active filters</span>} actions={<button>Apply</button>} />);
    expect(screen.getByText('Active filters')).toBeInTheDocument();
  });

  it.each([
    { ariaLabel: 'Utility bar region', expectRegion: true },
    { ariaLabel: undefined, expectRegion: false }
  ])('applies region role only when labelled', ({ ariaLabel, expectRegion }) => {
    render(
      <FloatingBar
        ariaLabel={ariaLabel}
        content={<span>Summary</span>}
        actions={<button>Action</button>}
      />
    );
    const region = screen.queryByRole('region');
    expect(Boolean(region)).toBe(expectRegion);
  });

  it.each([
    { isScrollable: false, expected: false },
    { isScrollable: true, expected: true }
  ])('renders scroll buttons only when isScrollable=%s', ({ isScrollable, expected }) => {
    render(
      <FloatingBar
        isScrollable={isScrollable}
        content={<span>Summary</span>}
        actions={<button>Action</button>}
      />
    );
    const leftButton = screen.queryByRole('button', { name: 'Scroll left' });
    expect(Boolean(leftButton)).toBe(expected);
  });

  it('disables scroll buttons when handlers are not provided', () => {
    render(
      <FloatingBar
        isScrollable
        content={<span>Summary</span>}
        actions={<button>Action</button>}
      />
    );
    const buttons = screen.getAllByRole('button', { name: /Scroll/ });
    expect(buttons.every(button => (button as HTMLButtonElement).disabled)).toBe(true);
  });

  it('fires onLeftScroll when provided', () => {
    const handleLeftScroll = jest.fn();
    render(
      <FloatingBar
        isScrollable
        onLeftScroll={handleLeftScroll}
        content={<span>Summary</span>}
        actions={<button>Action</button>}
      />
    );
    const leftButton = screen.getByRole('button', { name: 'Scroll left' });
    fireEvent.click(leftButton);
    expect(handleLeftScroll).toHaveBeenCalledTimes(1);
  });

  it('fires onRightScroll when provided', () => {
    const handleRightScroll = jest.fn();
    render(
      <FloatingBar
        isScrollable
        onRightScroll={handleRightScroll}
        content={<span>Summary</span>}
        actions={<button>Action</button>}
      />
    );
    const rightButton = screen.getByRole('button', { name: 'Scroll right' });
    fireEvent.click(rightButton);
    expect(handleRightScroll).toHaveBeenCalledTimes(1);
  });

  it('renders content and actions verbatim', () => {
    const contentText = '3 filters applied';
    const actionText = 'Clear all';
    render(
      <FloatingBar
        content={<span data-testid="content-slot">{contentText}</span>}
        actions={<button data-testid="actions-slot">{actionText}</button>}
      />
    );
    const contentNode = screen.getByTestId('content-slot');
    const actionsNode = screen.getByTestId('actions-slot');
    expect([contentNode.textContent, actionsNode.textContent]).toEqual([
      contentText,
      actionText
    ]);
  });
});
